function ToolbarDemo() {
  const [focusedIdx, setFocusedIdx] = useState(0);
  const [bold, setBold] = useState(false);
  const [italic, setItalic] = useState(false);
  const itemRefs = useRef([]);
  const items = [
    { label: '굵게', action: () => setBold(b => !b), pressed: bold },
    { label: '기울임', action: () => setItalic(i => !i), pressed: italic },
    { label: '취소선', action: () => {}, pressed: false },
  ];

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowRight') {
      e.preventDefault();
      const next = (focusedIdx + 1) % items.length;
      setFocusedIdx(next);
      itemRefs.current[next]?.focus();
    } else if (e.key === 'ArrowLeft') {
      e.preventDefault();
      const prev = (focusedIdx - 1 + items.length) % items.length;
      setFocusedIdx(prev);
      itemRefs.current[prev]?.focus();
    }
  };

  return (
    <div
      role="toolbar"
      aria-label="텍스트 서식"
      onKeyDown={handleKeyDown}
    >
      {items.map((item, i) => (
        <button
          key={item.label}
          ref={el => itemRefs.current[i] = el}
          tabIndex={focusedIdx === i ? 0 : -1}
          aria-pressed={item.pressed}
          onClick={item.action}
        >
          {item.label}
        </button>
      ))}
    </div>
  );
}
